	isPrime := func(num int64) bool {
		if num <= 1 {
			return false
		}
		if num == 2 {
			return true
		}
		if num%2 == 0 {
			return false
		}
		for i := int64(3); i*i <= num; i += 2 {
			if num%i == 0 {
				return false
			}
		}
		return true
	}

	// Helper function to get all primes up to a number
	getPrimes := func(num int64) []int64 {
		if num <= 1 {
			return []int64{}
		}
