		index, steps := queue[0][0], queue[0][1]
		queue = queue[1:]

		if index == n-1 {
			return int64(steps)
		}

		visited[index] = true

		// Move to adjacent cells
		for _, nextIndex := range []int{-1, 1} {
			if nextIndex >= 0 && nextIndex < n && !visited[nextIndex] {
				queue = append(queue, [2]int{nextIndex, steps + 1})
			}
		}

		// Prime teleport
		if isPrime(nums[index]) {
			primes := getPrimes(nums[index])
			for _, p := range primes {
				for j := 0; j < n; j++ {
					if j != index && nums[j]%p == 0 {
						queue = append(queue, [2]int{j, steps + 1})
					}
				}
			}
		}
	}

	return -1
}
